/// The UTC offset (seconds) for canonical zone `name` at `epoch_s` (epoch
/// seconds), or null if the zone is not tabulated. Binary-searches the zone's
/// transitions for the latest one at or before `epoch_s`.
pub fn offsetAt(name: []const u8, epoch_s: i64) ?i32 {
    const zone = for (zones) |z| {
        if (std.mem.eql(u8, z.name, name)) break z;
    } else return null;
    if (zone.trans.len == 0) return null;
    var lo: usize = 0;
    var hi: usize = zone.trans.len;
    while (lo < hi) {
        const mid = lo + (hi - lo) / 2;
        if (zone.trans[mid].at <= epoch_s) lo = mid + 1 else hi = mid;
    }
    // lo is the first transition strictly after epoch_s; the one before it holds.
    const idx = if (lo == 0) 0 else lo - 1;
    return zone.trans[idx].off;
}
